import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import Footer from '../components/Footer';
import { useCart } from '../context/CartContext';
import './Shop.css';
import './Swimwear.css';

// ── Product definitions with real images ──────────────────────────────────────
const PRODUCTS = [
  {
    id: 'blue-boitumelo',
    slug: 'blue-boitumelo-bikini',
    name: 'Blue Boitumelo',
    subtitle: 'Triangle Bikini Set',
    price: 750,
    compare_at_price: null,
    description: 'A show-stopping blue and white triangle bikini set with rope-tie detailing. Shot on the shores of Mauritius, this set was made for the woman who commands every room — and every beach.',
    fabric_care: '80% Nylon, 20% Elastane. Rinse in cold water after use. Do not bleach. Lay flat to dry.',
    sizing_fit: 'Runs true to size. Model wears a size M. Ties are fully adjustable for a custom fit.',
    images: [
      { id: 1, src: '/boit1.jpeg', label: 'Front' },
      { id: 2, src: '/boit2.jpeg', label: 'Side' },
      { id: 3, src: '/boit3.jpeg', label: 'Side 2' },
      { id: 4, src: '/boit4.jpeg', label: 'Detail' },
    ],
    featured: true,
  },
  {
    id: 'lv-print-bikini',
    slug: 'lv-print-bikini',
    name: 'Luxe Print',
    subtitle: 'Triangle Bikini Set',
    price: 850,
    compare_at_price: null,
    description: 'Bold luxury-print triangle bikini. Front and back gold-hardware halter ties. Shot at a rooftop infinity pool in Dubai.',
    fabric_care: '80% Nylon, 20% Elastane. Rinse in cold water. Do not bleach.',
    sizing_fit: 'True to size. Fully adjustable halter ties.',
    images: [
      { id: 1, src: '/lv1.jpeg', label: 'Front' },
      { id: 2, src: '/lv2.jpeg', label: 'Back'  },
    ],
    featured: false,
  },
  {
    id: 'black-cutout',
    slug: 'black-cutout-one-piece',
    name: 'Noir Cut-Out',
    subtitle: 'One-Shoulder Swimsuit',
    price: 680,
    compare_at_price: 850,
    description: 'Sleek one-shoulder cut-out swimsuit with gold ring hardware. A true statement piece — elegance and edge in one silhouette.',
    fabric_care: '82% Polyamide, 18% Elastane. Hand wash cold. Do not tumble dry.',
    sizing_fit: 'Runs slightly small. We recommend sizing up. Model wears a size M.',
    images: [
      { id: 1, src: '/se1.jpeg', label: 'Front' },
      { id: 2, src: '/se2.jpeg', label: 'Back'  },
    ],
    featured: false,
  },
];

const SIZES = ['XS', 'S', 'M', 'L', 'XL', 'XXL'];
const OUT_OF_STOCK = ['XXL'];
const ACC_SECTIONS = (p) => [
  { key: 'description', label: 'Description',       body: p.description },
  { key: 'fabric',      label: 'Fabric & Care',     body: p.fabric_care },
  { key: 'sizing',      label: 'Sizing & Fit',      body: p.sizing_fit },
  { key: 'delivery',    label: 'Delivery & Returns', body: 'Standard delivery R95, free on orders over R850. Delivered within 3–5 working days. Returns accepted within 30 days — unworn, tags attached.' },
];

// ── Product Detail Panel ───────────────────────────────────────────────────────
function ProductPanel({ product }) {
  const { addToCart }               = useCart();
  const [activeImg, setActiveImg]   = useState(0);
  const [selSize, setSelSize]       = useState('');
  const [qty, setQty]               = useState(1);
  const [wishlisted, setWishlisted] = useState(false);
  const [added, setAdded]           = useState(false);
  const [sizeError, setSizeError]   = useState(false);
  const [zoomed, setZoomed]         = useState(false);
  const [openAcc, setOpenAcc]       = useState('description');

  const isOnSale = product.compare_at_price && product.compare_at_price > product.price;
  const discPct  = isOnSale ? Math.round((1 - product.price / product.compare_at_price) * 100) : 0;

  const handleAdd = () => {
    if (!selSize) { setSizeError(true); setTimeout(() => setSizeError(false), 2000); return; }
    addToCart({
      id: product.id, slug: product.slug, name: product.name,
      price: product.price, main_image_url: product.images[0]?.src,
    }, selSize, '', qty);
    setAdded(true);
    setTimeout(() => setAdded(false), 2200);
  };

  const nav = (d) => {
    const next = Math.max(0, Math.min(product.images.length - 1, activeImg + d));
    setActiveImg(next);
    setZoomed(false);
  };

  const toggleAcc = (key) => setOpenAcc(v => v === key ? '' : key);

  return (
    <div className="sw-featured">
      {/* Gallery */}
      <div className="sw-gallery">
        <div className="sw-gallery__thumbs">
          {product.images.map((img, i) => (
            <button key={img.id} className={`sw-thumb${activeImg === i ? ' on' : ''}`} onClick={() => { setActiveImg(i); setZoomed(false); }}>
              <img src={img.src} alt={img.label} />
              <span className="sw-thumb__label">{img.label}</span>
            </button>
          ))}
        </div>
        <div className={`sw-gallery__main${zoomed ? ' zoomed' : ''}`} onClick={() => setZoomed(v => !v)}>
          <img src={product.images[activeImg]?.src} alt={`${product.name} — ${product.images[activeImg]?.label}`} className="sw-gallery__img" />
          <span className="sw-gallery__counter">{activeImg + 1} / {product.images.length}</span>
          <span className="sw-gallery__zoom-hint">
            <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
              <line x1="11" y1="8" x2="11" y2="14"/><line x1="8" y1="11" x2="14" y2="11"/>
            </svg>
            {zoomed ? 'Click to zoom out' : 'Click to zoom'}
          </span>
          {activeImg > 0 && (
            <button className="sw-gallery__arrow sw-gallery__arrow--prev" onClick={e => { e.stopPropagation(); nav(-1); }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><polyline points="15 18 9 12 15 6"/></svg>
            </button>
          )}
          {activeImg < product.images.length - 1 && (
            <button className="sw-gallery__arrow sw-gallery__arrow--next" onClick={e => { e.stopPropagation(); nav(1); }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><polyline points="9 18 15 12 9 6"/></svg>
            </button>
          )}
        </div>
      </div>

      {/* Info */}
      <div className="sw-info">
        <div className="sw-info__top">
          <p className="sw-info__eyebrow">Dream In Lace · Swimwear</p>
          <button className="sw-share">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.4">
              <circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/>
              <line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/>
              <line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/>
            </svg>
            Share
          </button>
        </div>

        <h1 className="sw-info__name">{product.name}</h1>
        <p className="sw-info__subtitle">{product.subtitle}</p>

        {/* Stars */}
        <div className="sw-rating">
          {[1,2,3,4,5].map(s => (
            <svg key={s} width="13" height="13" viewBox="0 0 24 24" fill="#b8a08a" stroke="#b8a08a" strokeWidth="1">
              <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/>
            </svg>
          ))}
          <span className="sw-rating__count">18 reviews</span>
        </div>

        {/* Price */}
        <div className="sw-price-row">
          <span className="sw-price">R {product.price.toLocaleString()}</span>
          {isOnSale && <span className="sw-price-was">R {product.compare_at_price.toLocaleString()}</span>}
          {isOnSale && <span className="sw-price-save">Save {discPct}%</span>}
        </div>

        {/* View pills */}
        <div className="sw-view-pills">
          {product.images.map((img, i) => (
            <button key={img.id} className={`sw-view-pill${activeImg === i ? ' on' : ''}`}
              onClick={() => { setActiveImg(i); setZoomed(false); }}>
              {img.label} view
            </button>
          ))}
        </div>

        {/* Size */}
        <div className={`sw-field-label${sizeError ? ' error' : ''}`}>
          Size {selSize && <span>{selSize}</span>}
          {sizeError && <span className="sw-size-error">Please select a size</span>}
        </div>
        <div className="sw-sizes">
          {SIZES.map(s => {
            const out = OUT_OF_STOCK.includes(s);
            return (
              <button key={s} className={`sw-sz${selSize === s ? ' on' : ''}${out ? ' out' : ''}`}
                onClick={() => !out && setSelSize(s)}>
                {s}
              </button>
            );
          })}
        </div>
        <button className="sw-size-guide">Size guide →</button>

        {/* Qty */}
        <div className="sw-field-label" style={{ marginBottom: '.5rem' }}>Quantity</div>
        <div className="sw-qty">
          <button className="sw-qty__btn" onClick={() => setQty(v => Math.max(1, v - 1))}>−</button>
          <span className="sw-qty__val">{qty}</span>
          <button className="sw-qty__btn" onClick={() => setQty(v => v + 1)}>+</button>
        </div>

        {/* CTA */}
        <div className="sw-cta">
          <button className={`sw-add-btn${added ? ' added' : ''}`} onClick={handleAdd}>
            {added ? 'Added to Bag ✓' : 'Add to Bag'}
          </button>
          <button className={`sw-wish-btn${wishlisted ? ' on' : ''}`} onClick={() => setWishlisted(v => !v)}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill={wishlisted ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="1.4">
              <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
            </svg>
          </button>
        </div>

        {/* Trust */}
        <div className="sw-trust">
          {[
            { icon: 'M5 12h14M12 5l7 7-7 7', t: 'Free delivery', s: 'Over R850' },
            { icon: 'M23 4 23 10 17 10M20.49 15a9 9 0 11-2.12-9.36L23 10', t: '30-day returns', s: 'Easy & free' },
            { icon: 'M3 11h18v11H3zM7 11V7a5 5 0 0110 0v4', t: 'Secure checkout', s: 'SSL encrypted' },
          ].map(u => (
            <div className="sw-trust__item" key={u.t}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.3"><path d={u.icon}/></svg>
              <div><p className="sw-trust__title">{u.t}</p><p className="sw-trust__sub">{u.s}</p></div>
            </div>
          ))}
        </div>

        {/* Accordion */}
        <div className="sw-accordion">
          {ACC_SECTIONS(product).map(({ key, label, body }) => (
            <div className="sw-acc__row" key={key}>
              <button className={`sw-acc__head${openAcc === key ? ' open' : ''}`} onClick={() => toggleAcc(key)}>
                {label}
                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"
                  style={{ transition: 'transform .25s', transform: openAcc === key ? 'rotate(180deg)' : 'none', flexShrink: 0 }}>
                  <polyline points="6 9 12 15 18 9"/>
                </svg>
              </button>
              {openAcc === key && <div className="sw-acc__body">{body}</div>}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Main Swimwear Page ─────────────────────────────────────────────────────────
export default function Swimwear() {
  const navigate = useNavigate();
  const [activeProduct, setActiveProduct] = useState(0);

  return (
    <>
      <Header />

      {/* Breadcrumb */}
      <div className="breadcrumb">
        <span className="bc" onClick={() => navigate('/')}>Home</span>
        <span className="bc-sep">›</span>
        <span className="bc cur">Swimwear</span>
      </div>

      {/* Product selector tabs */}
      <div className="sw-product-tabs">
        {PRODUCTS.map((p, i) => (
          <button
            key={p.id}
            className={`sw-product-tab${activeProduct === i ? ' on' : ''}`}
            onClick={() => setActiveProduct(i)}
          >
            <div className="sw-product-tab__img">
              <img src={p.images[0].src} alt={p.name} />
            </div>
            <div className="sw-product-tab__info">
              <span className="sw-product-tab__name">{p.name}</span>
              <span className="sw-product-tab__price">R {p.price.toLocaleString()}</span>
            </div>
            {p.compare_at_price && <span className="sw-product-tab__badge">Sale</span>}
          </button>
        ))}
      </div>

      {/* Active product detail */}
      <ProductPanel key={PRODUCTS[activeProduct].id} product={PRODUCTS[activeProduct]} />

      {/* Other products strip */}
      <section className="sw-more">
        <div className="page-inner">
          <div className="section-header">
            <h2 className="section-title">More Swimwear</h2>
            <Link to="/swimwear" className="section-link">View all</Link>
          </div>
          <div className="sw-more__grid">
            {PRODUCTS.filter((_, i) => i !== activeProduct).map(p => (
              <div key={p.id} className="sw-more__card" onClick={() => { setActiveProduct(PRODUCTS.indexOf(p)); window.scrollTo({ top: 0, behavior: 'smooth' }); }}>
                <div className="sw-more__card-img">
                  <img src={p.images[0].src} alt={p.name} loading="lazy" />
                </div>
                <div className="sw-more__card-info">
                  <div>
                    <p className="sw-more__card-name">{p.name}</p>
                    <p className="sw-more__card-sub">{p.subtitle}</p>
                  </div>
                  <p className="sw-more__card-price">R {p.price.toLocaleString()}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
}
